def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time_between(p1, p2):
        return np.linalg.norm(p1 - p2) / truck_speed

    def time_until_window(opens):
        return max(0, opens - current_time)

    best_node = None
    min_cost = float('inf')

    # Evaluate each unvisited customer
    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = travel_time_between(cur_truck_pos, customer_pos)
        start_window, end_window = time_windows[i]
        wait_time = time_until_window(start_window)

        # Calculate quadratic penalty for missed time windows
        if current_time + travel_time + wait_time > end_window:
            penalty_time = ((current_time + travel_time + wait_time - end_window) ** 2) * 5
        else:
            penalty_time = 0

        # Cost function considers distance primarily, time next, and quadratic penalties last
        cost = (travel_time ** 2) + wait_time + penalty_time

        # Update best node based on minimal cost
        if cost < min_cost:
            min_cost = cost
            best_node = i

    # Consider waiting as an option if all available routes incur high costs
    if best_node is None:
        return 'None'

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    if len(unvisited_customers) == 0:
        return None

    time_to_reach = [(calculate_distance(cur_truck_pos, customer) / truck_speed) for customer in unvisited_customers]
    arrival_times = [current_time + time for time in time_to_reach]

    scores = []

    # Calculate a score for each customer based on time windows and distances
    for idx, customer in enumerate(unvisited_customers):
        window_start, window_end = time_windows[idx]
        arrival_time = arrival_times[idx]

        if arrival_time < window_start:
            wait_time = window_start - arrival_time
            score = wait_time + time_to_reach[idx] * 1.2  # Penalty for waiting, but less than missing the window
        elif arrival_time > window_end:
            penalty = (arrival_time - window_end) * 10  # High penalty for missing the window
            score = penalty + time_to_reach[idx]
        else:
            score = time_to_reach[idx]  # No penalty if within the window

        scores.append(score)

    # Find the best customer to minimize the score
    best_node = np.argmin(scores)

    return best_node
